// Define which locations to check and their PIT tokens
// REPLACE these with actual location IDs and tokens when hooking up
const locations = [
  // { id: 'LOCATION_ID_1', name: 'Client Name', token: 'pit-xxx' },
  // { id: 'LOCATION_ID_2', name: 'Client Name', token: 'pit-xxx' },
];

// Calculate date thresholds
const now = new Date();
const day30 = new Date(now - 30 * 24 * 60 * 60 * 1000).toISOString();
const day60 = new Date(now - 60 * 24 * 60 * 60 * 1000).toISOString();
const day90 = new Date(now - 90 * 24 * 60 * 60 * 1000).toISOString();

// For now, output the config so it's ready to wire up
return [{
  json: {
    locations,
    thresholds: {
      day30,
      day60,
      day90
    },
    maxPerDay: 10,
    dryRun: true
  }
}];

// Query GHL contacts for stale leads
// This node searches each location for contacts that:
// - Have NOT been contacted in 30/60/90 days
// - Are tagged as curious, price_shopper, or similar
// - Are NOT tagged as appointment-set, closed-won, or do-not-contact
// - Have NOT already been reactivated in this cycle

const config = $input.first().json;
const results = [];

for (const location of config.locations) {
  // Search contacts via GHL API
  // In production, use this.helpers.httpRequest() for each location
  // For now, build the query structure

  const searchPayload = {
    locationId: location.id,
    filters: [
      {
        field: 'tags',
        operator: 'contains',
        value: ['curious', 'price_shopper', 'busy_lead']
      },
      {
        field: 'tags',
        operator: 'not_contains',
        value: ['appointment-set', 'closed-won', 'do-not-contact', 'reactivation-sent']
      }
    ],
    pageLimit: config.maxPerDay
  };

  results.push({
    location: location.name,
    locationId: location.id,
    token: location.token,
    searchPayload,
    threshold: config.thresholds
  });
}

if (results.length === 0) {
  // No locations configured yet - output placeholder
  results.push({
    location: 'NOT_CONFIGURED',
    locationId: '',
    note: 'Add location IDs and PIT tokens to the Config node to activate'
  });
}

return results.map(r => ({ json: r }));

// Build reactivation messages based on how long since last contact
// 30 days = soft check-in
// 60 days = value reminder
// 90 days = last chance / door closing

const data = $input.first().json;

if (!data.locationId || data.location === 'NOT_CONFIGURED') {
  return [{ json: { skip: true, reason: 'No locations configured' } }];
}

// Message templates by tier
const messages = {
  day30: [
    'Hey {{firstName}}, we chatted a while back about {{businessGoal}}. Still something you\'re thinking about? Happy to pick up where we left off.',
    'Hey {{firstName}}, just checking in - you mentioned you were interested in {{businessGoal}} last month. Anything changed? No pressure either way.',
  ],
  day60: [
    'Hey {{firstName}}, it\'s been a couple of months since we last spoke. A few spots have opened up if you\'re still interested in {{businessGoal}}. Want me to grab you one?',
    'Hey {{firstName}}, circling back on this - we\'ve had some great results recently with people in a similar position to you. Worth a quick chat if you\'re still thinking about it?',
  ],
  day90: [
    'Hey {{firstName}}, last check-in from me on this. If the timing\'s not right, totally understand. But if {{businessGoal}} is still on your radar, I can get you sorted this week. Just say the word.',
    'Hey {{firstName}}, I know it\'s been a while. If things have changed and this isn\'t for you anymore, no worries at all. But if you\'re still interested, the offer\'s still there. Reply and I\'ll sort a time.',
  ]
};

// Pick a random message from the appropriate tier
const tier = 'day30'; // Will be dynamic based on actual last contact date
const tierMessages = messages[tier];
const message = tierMessages[Math.floor(Math.random() * tierMessages.length)];

return [{
  json: {
    ...data,
    reactivationTier: tier,
    messageTemplate: message,
    tagsToAdd: ['reactivation-sent', `reactivation-${tier}`]
  }
}];

// In production: send via GHL conversation API
// For now: log what WOULD be sent

const data = $input.first().json;
const dryRun = true; // Set to false when ready to go live

if (dryRun) {
  return [{
    json: {
      ...data,
      action: 'DRY_RUN',
      wouldSend: data.messageTemplate,
      note: 'Set dryRun=false in Config node to send real messages'
    }
  }];
}

// Production send:
